# Stack all 22 vectors into matrix
names = list(raw.keys())
mat = np.stack([raw[n] for n in names])  # (22, 2560)
print(f"Matrix shape: {mat.shape}")

# Save hidden states
np.save(OUT_DIR / 'hidden_states_v2.npy', mat)

# Compute per-dimension variance across all 22 vectors
var = mat.var(axis=0)
np.save(OUT_DIR / 'variance_per_dim.npy', var)
print(f"Variance computed. Max={var.max():.1f}, Mean={var.mean():.1f}")

# Helper: cosine similarity
def cosine(a, b):
    a = a / (np.linalg.norm(a) + 1e-12)
    b = b / (np.linalg.norm(b) + 1e-12)
    return float(np.dot(a, b))

# ============================================================
# City routing: Q1 -> F1, Q2 -> F2, against F1-F9 (9 facts)
# Verb routing: Q11 -> F10, Q12 -> F11, against F10-F13 (4 facts)
# ============================================================
city_facts = ['F1','F2','F3','F4','F5','F6','F7','F8','F9']
verb_facts = ['F10','F11','F12','F13']

city_queries = {'Q1': 'F1', 'Q2': 'F2'}  # query -> expected
verb_queries  = {'Q11': 'F10', 'Q12': 'F11'}

def route(q_name, fact_pool, method_fn, label=""):
    q = method_fn(raw[q_name], q_name)
    sims = {}
    for fn in fact_pool:
        f = method_fn(raw[fn], fn)
        sims[fn] = cosine(q, f)
    best = max(sims, key=sims.get)
    return best, sims

# Method 0: raw cosine
def m0_transform(v, name):
    return v

# Method 1: variance-weighted cosine variants
def make_m1(weights):
    def transform(v, name):
        return v * weights
    return transform

weights_sqrt = np.sqrt(var)
weights_log  = np.log1p(var)

def make_m1_topk(weights, K):
    top_k_idx = np.argsort(weights)[-K:]
    def transform(v, name):
        out = np.zeros_like(v)
        out[top_k_idx] = v[top_k_idx] * weights[top_k_idx]
        return out
    return transform

# Method 3: contrastive delta
def m3_city_transform(v, name):
    return v - raw['G_city']

def m3_verb_transform(v, name):
    return v - raw['G_verb']

# Method 3b: GF-delta (subtract matched single-fact+generic baseline)
gf_map = {'Q1': 'GF1', 'Q2': 'GF2', 'Q11': 'GF11', 'Q12': 'GF12'}
fact_gf_city = {fn: None for fn in city_facts}  # no per-fact GF for non-query facts
fact_gf_verb = {fn: None for fn in verb_facts}

# For facts use G_city/G_verb as baseline
def m3b_city_transform(v, name):
    # For query names, use GF baseline if available
    if name in gf_map:
        return v - raw[gf_map[name]]
    return v - raw['G_city']

def m3b_verb_transform(v, name):
    if name in gf_map:
        return v - raw[gf_map[name]]
    return v - raw['G_verb']

# Method 4: Fisher discriminant (entity-discriminating dims only)
# Use all city facts F1-F9 to compute within-class scatter
def compute_fisher_weights(fact_pool):
    X = np.stack([raw[fn] for fn in fact_pool])
    grand_mean = X.mean(axis=0)
    between = np.var(X, axis=0)  # variance across fact means
    within = np.zeros(2560)
    for fn in fact_pool:
        within += (raw[fn] - grand_mean)**2
    within /= len(fact_pool)
    # Fisher ratio: between / (within + eps)
    fisher = between / (within + 1e-6)
    return fisher

fisher_city = compute_fisher_weights(city_facts)
fisher_verb = compute_fisher_weights(verb_facts)

def make_m4(weights):
    def transform(v, name):
        return v * weights
    return transform

