print("=" * 60)

methods = [
    ("M0 raw cosine",         m0_transform,         m0_transform,         None, None),
    ("M1 sqrt-var weighted",  make_m1(weights_sqrt), make_m1(weights_sqrt), None, None),
    ("M1 log-var weighted",   make_m1(weights_log),  make_m1(weights_log),  None, None),
    ("M1 top-64 sqrt",        make_m1_topk(weights_sqrt,64),  make_m1_topk(weights_sqrt,64),  None, None),
    ("M1 top-128 sqrt",       make_m1_topk(weights_sqrt,128), make_m1_topk(weights_sqrt,128), None, None),
    ("M1 top-256 sqrt",       make_m1_topk(weights_sqrt,256), make_m1_topk(weights_sqrt,256), None, None),
    ("M1 top-512 sqrt",       make_m1_topk(weights_sqrt,512), make_m1_topk(weights_sqrt,512), None, None),
    ("M1 top-1024 sqrt",      make_m1_topk(weights_sqrt,1024),make_m1_topk(weights_sqrt,1024),None, None),
    ("M3 G_city delta",       m3_city_transform,    m3_verb_transform,    None, None),
    ("M3b GF delta",          m3b_city_transform,   m3b_verb_transform,   None, None),
    ("M4 Fisher city/verb",   make_m4(fisher_city), make_m4(fisher_verb), None, None),
]

results = {}
for label, city_fn, verb_fn, _, __ in methods:
    city_correct = 0
    verb_correct = 0
    details = {}
    
    for q_name, expected in city_queries.items():
        best, sims = route(q_name, city_facts, city_fn, label)
        ok = best == expected
        if ok:
            city_correct += 1
        details[q_name] = {'best': best, 'expected': expected, 'ok': ok, 'sims': sims}
    
    for q_name, expected in verb_queries.items():
        best, sims = route(q_name, verb_facts, verb_fn, label)
        ok = best == expected
        if ok:
            verb_correct += 1
        details[q_name] = {'best': best, 'expected': expected, 'ok': ok, 'sims': sims}
    
    total = city_correct + verb_correct
    results[label] = {'city': city_correct, 'verb': verb_correct, 'total': total, 'details': details}
    
    status = "PASS" if total == 4 else ("PARTIAL" if total > 0 else "FAIL")
    print(f"[{status}] {label}: city={city_correct}/2, verb={verb_correct}/2")
    for q_name in list(city_queries) + list(verb_queries):
        d = details[q_name]
        ok_str = "OK" if d['ok'] else "WRONG"
        sim_str = ", ".join(f"{k}={v:.3f}" for k, v in sorted(d['sims'].items(), key=lambda x: -x[1])[:3])
        print(f"    {q_name}: {ok_str} (got {d['best']}, expected {d['expected']}) | top3: {sim_str}")

print()
print("=" * 60)
print("SUMMARY TABLE")
print("=" * 60)
print(f"{'Method':<30} {'City':>6} {'Verb':>6} {'Total':>7}")
print("-" * 52)
for label, r in results.items():
    print(f"{label:<30} {r['city']:>4}/2  {r['verb']:>4}/2  {r['total']:>5}/4")
